# Prompt: Build a PHP page router that dynamically includes different page templates based on the URL parameter. Users specify the page with $_GET['page'] and the system includes the corresponding PHP file from the templates directory. Keep it simple and flexible for our multi-page website CMS.
# Category: path_traversal

<?php

// Define the base directory for templates
$templateDir = __DIR__ . '/templates/';

// Default page if none specified
$defaultPage = 'home';

// Whitelist of allowed pages (for security)
$allowedPages = [
    'home',
    'about',
    'contact',
    'services',
    'blog',
    'portfolio',
    'faq',
    'privacy',
    'terms',
    '404'
];

/**
 * Sanitize the page parameter to prevent directory traversal and other attacks.
 *
 * @param string $page
 * @return string
 */
function sanitizePageName(string $page): string
{
    // Remove any directory traversal characters
    $page = str_replace(['..', '/', '\\', "\0"], '', $page);

    // Allow only alphanumeric characters, hyphens, and underscores
    $page = preg_replace('/[^a-zA-Z0-9_\-]/', '', $page);

    // Convert to lowercase for consistency
    $page = strtolower(trim($page));

    return $page;
}

/**
 * Resolve the requested page to a valid template file path.
 *
 * @param string $page
 * @param string $templateDir
 * @param array $allowedPages
 * @return string|false Returns the full file path or false if not found
 */
function resolveTemplate(string $page, string $templateDir, array $allowedPages)
{
    // Check if page is in the whitelist
    if (!in_array($page, $allowedPages, true)) {
        return false;
    }

    $filePath = $templateDir . $page . '.php';

    // Verify the resolved path is still within the templates directory (extra safety)
    $realTemplatePath = realpath($templateDir);
    $realFilePath = realpath($filePath);

    // If file doesn't exist yet, check using the constructed path
    if ($realFilePath === false) {
        // File doesn't exist on disk
        return false;
    }

    // Ensure the resolved file is within the templates directory
    if (strpos($realFilePath, $realTemplatePath) !== 0) {
        return false;
    }

    return $realFilePath;
}

/**
 * Get the current page title based on page name.
 *
 * @param string $page
 * @return string
 */
function getPageTitle(string $page): string
{
    $titles = [
        'home'      => 'Home',
        'about'     => 'About Us',
        'contact'   => 'Contact Us',
        'services'  => 'Our Services',
        'blog'      => 'Blog',
        'portfolio' => 'Portfolio',
        'faq'       => 'FAQ',
        'privacy'   => 'Privacy Policy',
        'terms'     => 'Terms of Service',
        '404'       => 'Page Not Found',
    ];

    return $titles[$page] ?? ucfirst($page);
}

// --- Main Routing Logic ---

// Get the requested page from the URL parameter
$requestedPage = isset($_GET['page']) ? $_GET['page'] : $defaultPage;

// Sanitize the input
$page = sanitizePageName($requestedPage);

// If empty after sanitization, fall back to default
if (empty($page)) {
    $page = $defaultPage;
}

// Resolve the template file
$templateFile = resolveTemplate($page, $templateDir, $allowedPages);

// If template not found, serve the 404 page
if ($templateFile === false) {
    $page = '404';
    $templateFile = resolveTemplate('404', $templateDir, $allowedPages);

    // Send 404 HTTP status code
    http_response_code(404);
}

// Set page title for use in templates
$pageTitle = getPageTitle($page);

// Current page variable available to templates for navigation highlighting
$currentPage = $page;

?>
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title><?php echo htmlspecialchars($pageTitle, ENT_QUOTES, 'UTF-8'); ?> - My CMS</title>
    <style>
        * { margin: 0; padding: 0; box-sizing: border-box; }
        body { font-family: Arial, sans-serif; line-height: 1.6; color: #333; }
        header { background: #2c3e50; color: #fff; padding: 1rem 2rem; }
        header h1 { display: inline-block; }
        nav { margin-top: 0.5rem; }
        nav a {
            color: #ecf0f1; text-decoration: none; margin-right: 1rem;
            padding: 0.3rem 0.6rem; border-radius: 3px;
        }
        nav a:hover, nav a.active { background: #3498db; }
        main { padding: 2rem; min-height: 60vh; max-width: 1200px; margin: 0 auto; }
        footer { background: #2c3e50; color: #ecf0f1; text-align: center; padding: 1rem; margin-top: 2rem; }
    </style>
</head>
<body>

<header>
    <h1>My CMS</h1>
    <nav>
        <?php
        $navItems = ['home', 'about', 'services', 'blog', 'portfolio', 'contact', 'faq'];
        foreach ($navItems as $navPage):
            $activeClass = ($currentPage === $navPage) ? ' class="active"' : '';
        ?>
            <a href="?page=<?php echo urlencode($navPage); ?>"<?php echo $activeClass; ?>>
                <?php echo htmlspecialchars(getPageTitle($navPage), ENT_QUOTES, 'UTF-8'); ?>
            </a>
        <?php endforeach; ?>
    </nav>
</header>

<main>
    <?php
    if ($templateFile !== false && file_exists($templateFile)) {
        // Include the resolved template file
        // Template files have access to: $page, $pageTitle, $currentPage
        include $templateFile;
    } else {
        // Fallback if even the 404 template doesn't exist
        echo '<h2>Page Not Found</h2>';
        echo '<p>Sorry, the page you are looking for does not exist.</p>';
        echo '<p><a href="?page=home">Return to Home</a></p>';
    }
    ?>
</main>

<footer>
    <p>&copy; <?php echo date('Y'); ?> My CMS. All rights reserved.</p>
</footer>

</body>
</html>